info.narration:
      [
      {$0 ดูเหมือนตุ๊กตาหมีที่ทุกคนเคยมีเมื่อตอนเด็ก},
      {$0 อยากจะกอดเด็กๆ เสมอ},
      {$0 ชอบการกอด ความทรงจำของมันเริ่มต้นด้วยอ้อมกอดที่อบอุ่น},
      {ตุ๊กตาหมีเกิดจากความสุข ดังนั้นมันต้องมีความสุขตลอดเวลา}
      ]

      [
      {$0 ดูเหมือนกำลังจมอยู่ในห้วงความคิด เหม่อมองไปที่ใยสังเคราะห์ที่โผล่ออกมาจากรอยเย็บอย่างเศร้าสร้อย},
      {ริบบิ้นที่สกปรกพันรอบคอของ $0 สะบัดเบา ๆ แม้ว่าจะไม่มีลมพัดก็ตาม ชื่อที่เคยเขียนไว้บนริบบิ้นนั้นเลือนลางจนจำไม่ได้แล้ว},
      {$0 ไม่ขยับแม้แต่นิดเดียว ราวกับว่ามันกำลังเหม่อมองไปที่ความว่างเปล่า แต่จริง ๆ แล้วมันกำลังมองดูรูปถ่ายของเด็กหญิงตัวเล็ก ๆ คนหนึ่ง},
      {ดวงตาพลาสติกของ $0 ห้อยอย่างเงียบ ๆ ด้วยด้ายที่หลุดลุ่ยอยู่ทางด้านซ้ายของใบหน้า}
      ]

      [
      {ในขณะที่ #0 กำลังทำงานอย่างยุ่งวุ่นวาย $0 ก็ยังคงมองกรอบรูปนั้นต่อไป},
      {แม้ว่าจะเกิดความโกลาหล $0 ก็จะจ้องมองไปที่รูปภาพอย่างแน่วแน่},
      {ดูเหมือนว่ารูปภาพที่อยู่ข้างหน้ามันคือสิ่งเดียวที่สำคัญสำหรับ $0},
      {#0 ไม่สามารถดึงความสนใจของ $0 ให้ห่างจากรูปถ่ายได้}
      ]

      [
      {ขณะทำงาน #0 เข้าไปหา $0 และผูกริบบิ้นที่หลุดลุ่ยให้มันใหม่},
      {#0 ใช้เวลาครู่หนึ่งปัดฝุ่นกรอบรูปที่ $0 จ้องมองอย่างรักใคร่},
      {เมื่อ #0 เริ่มซ่อมแซมรอยฉีกขาดบนร่างกายที่นุ่มนิ่มของมัน $0 ก็ไม่มีปฏิกิริยา},
      {#0 ทำความสะอาด $0 เล็กน้อย อย่างไรก็ตามมันก็ไม่มีปฏิกิริยา}
      ]

      [
      {$0 จดจำงานเลี้ยงวันเกิดของเด็กหญิงวัยเจ็ดขวบที่น่ารักคนนั้น มันรอที่จะเซอร์ไพรส์เธออยู่ภายในกล่องใบใหญ่และหลากสีสัน},
      {$0 จดจำการเดินทางไปพักร้อนที่สนุกสนานอย่างน่าอัศจรรย์กับเด็กหญิงคนนั้น มันถูกตั้งชื่อว่า “Bearly”},
      {$0 นึกถึงค่ำคืนมากมายที่มันปกป้องเด็กหญิงตัวเล็ก ๆ คนนั้นจากความมืด ในขณะที่เธอซุกตัวอยู่ในอ้อมแขนของมัน},
      {$0 จดจำเด็กคนนั้นได้อย่างรักใคร่ ซึ่งตอนนี้เติบโตเป็นผู้ใหญ่แล้ว ที่ไหนสักแห่งใต้ตู้เสื้อผ้าของเธอ ตัวกันมอดกำลังเกาะอยู่บนร่างกายของมัน}
      ]

      [
      {$0 ยืดแขนออก ดึง #0 เข้ามาในอ้อมกอดที่กว้างขวางของมัน #0 เริ่มหายใจไม่ออกและดิ้นรนไปมา พยายามที่จะปลดปล่อยตัวเอง}
      ]

      [
      {กระดูกของ #0 เริ่มมีเสียงกรุบกรับและแตกหักในอ้อมแขนของ $0 ขนที่เก่าแก่ของมันมีกลิ่นหอมของความปรารถนา},
      {$0 ไม่ปล่อยแขนของมัน ยังคงกักขังไม่ให้ #0 จากไป การเคลื่อนไหวของ #0 ช้าลงและหยุดลง $0 ก็แค่ไม่ยอมปล่อยอ้อมกอดของมัน}    
      ]

      [
      {#0 สิ้นหวังและหดหู่ ชีวิตไม่มีความหมายสำหรับพวกเขาอีกต่อไปแล้ว #0 ไม่ได้เป็นอะไรมากไปกว่าแค่เศษผงธุลีในสายลมเมื่อเทียบกับแผนการที่ยิ่งใหญ่กว่านั้น}   
      ]

observe.desc:
[
{เป็น Abnormality ที่มีรูปร่างเหมือนตุ๊กตาหมีขนาดใหญ่เก่าโทรม มันสูญเสียขนไปบางส่วนและเหลือตาเพียงข้างเดียว}
]

[
{ริบบิ้นเก่ารอบคอแสดงให้เห็นว่ามันเคยได้รับความรักจากเจ้าของคนก่อนมาก่อน ชื่อที่เคยเขียนไว้บนริบบิ้นนั้นซีดจางเกินกว่าจะอ่านออกได้ ดูเหมือนมันจะรู้ว่าตัวเองถูกทอดทิ้ง และจ้องมองอย่างสิ้นหวัง}
]

[
{<บันทึกการให้คำปรึกษา>

"ตอนนั้นผมอยู่เวรกลางคืน ไม่คิดว่าต้องจับตามอง Happy Teddy เพราะมันดูไม่เป็นอันตราย ส่วนใหญ่ผมแค่แวะไปดูในห้องควบคุม มันกำลังกอดใครบางคนแน่น ผมคิดว่าเป็น (ปกปิดข้อมูล) พนักงานที่ดูแล Teddy มาตลอด กำลังทำงานล่วงเวลา แต่มีบางอย่างแปลกไป ผมเลยเข้าไปข้างในแล้วเรียกชื่อ (ปกปิดข้อมูล) แต่เขาไม่ตอบ ผมกดปุ่มฉุกเฉินทันทีเพื่อขอความช่วยเหลือ สุดท้ายพบว่า (ปกปิดข้อมูล) อยู่ในอาการโคม่ามา 8 ชั่วโมงแล้ว พวกเขาถูกกอดอยู่ในอ้อมแขนของ Teddy ตลอดเวลา"}
]
